DROP TABLE IF EXISTS `ingresos_cobranza`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ingresos_cobranza` (
  `id_cobro` int NOT NULL AUTO_INCREMENT,
  `folio_factura` varchar(50) DEFAULT NULL,
  `cliente` varchar(100) NOT NULL,
  `fecha_promesa_pago` date NOT NULL,
  `fecha_real_pago` date DEFAULT NULL,
  `monto_cobro` decimal(15,2) NOT NULL,
  `probabilidad` enum('ALTA','MEDIA','BAJA') DEFAULT 'ALTA',
  `cuenta_destino` varchar(50) DEFAULT NULL COMMENT 'Santander, BBVA, etc.',
  `estatus` enum('PENDIENTE','COBRADO','CANCELADO') DEFAULT 'PENDIENTE',
  PRIMARY KEY (`id_cobro`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
