/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `asignar_folio_proyeccion` BEFORE INSERT ON `proyecciones_cliente` FOR EACH ROW BEGIN
    DECLARE nuevo_folio VARCHAR(10);
    DECLARE folio_existente VARCHAR(30);
    DECLARE fecha_actual DATETIME;
    DECLARE ultimo_folio_num INT;

    -- Redondear la fecha actual sin segundos para agruper por minuto
    SET fecha_actual = DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:00');

    -- Buscar si ya existe un folio para ese cliente en esa misma fecha (al minuto)
    SELECT folio INTO folio_existente
    FROM proyecciones_cliente
    WHERE id_cliente = NEW.id_cliente
      AND DATE_FORMAT(fecha_registro, '%Y-%m-%d %H:%i:00') = fecha_actual
    LIMIT 1;

    IF folio_existente IS NOT NULL THEN
        -- Si ya existe un folio para ese cliente y minuto, usarlo
        SET NEW.folio = folio_existente;
        SET NEW.fecha_registro = fecha_actual;
    ELSE
        -- Si no existe, crear un nuevo folio
        SELECT IFNULL(MAX(CAST(SUBSTRING(folio, 4) AS UNSIGNED)), 0) + 1
        INTO ultimo_folio_num
        FROM proyecciones_cliente;

        SET nuevo_folio = CONCAT('FOL', LPAD(ultimo_folio_num, 4, '0'));

        -- Asignar nuevos valores
        SET NEW.folio = nuevo_folio;
        SET NEW.fecha_registro = fecha_actual;
    END IF;
END */;;
DELIMITER ;
