/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `actualizar_proyeccion_global_cliente_insert` AFTER INSERT ON `proyecciones_cliente` FOR EACH ROW BEGIN
    DECLARE total_cantidad INT;
    DECLARE total_importe DECIMAL(10,2);
    DECLARE precio_publico DECIMAL(10,2);

    -- Obtener precio público para evitar usarlo
    SELECT precio_publico_con_iva INTO precio_publico 
    FROM proyecciones_ventas WHERE id = NEW.id_proyeccion;

    -- Calcular total de cantidades (actualizado con nuevas quincenas)
    SELECT 
        IFNULL(SUM(q1_sep_2025), 0) + IFNULL(SUM(q2_sep_2025), 0) + 
        IFNULL(SUM(q1_oct_2025), 0) + IFNULL(SUM(q2_oct_2025), 0) + 
        IFNULL(SUM(q1_nov_2025), 0) + IFNULL(SUM(q2_nov_2025), 0) + 
        IFNULL(SUM(q1_dic_2025), 0) + IFNULL(SUM(q2_dic_2025), 0) +
        IFNULL(SUM(q1_mar_2026), 0) + IFNULL(SUM(q2_mar_2026), 0) + 
        IFNULL(SUM(q1_abr_2026), 0) + IFNULL(SUM(q2_abr_2026), 0) + 
        IFNULL(SUM(q1_may_2026), 0) + IFNULL(SUM(q2_may_2026), 0)
    INTO total_cantidad
    FROM proyecciones_cliente 
    WHERE id_proyeccion = NEW.id_proyeccion;

    -- Calcular total del importe usando precio_aplicado (actualizado)
    SELECT 
        SUM(
            (
                IFNULL(q1_sep_2025, 0) + IFNULL(q2_sep_2025, 0) +
                IFNULL(q1_oct_2025, 0) + IFNULL(q2_oct_2025, 0) +
                IFNULL(q1_nov_2025, 0) + IFNULL(q2_nov_2025, 0) +
                IFNULL(q1_dic_2025, 0) + IFNULL(q2_dic_2025, 0) +
                IFNULL(q1_mar_2026, 0) + IFNULL(q2_mar_2026, 0) +
                IFNULL(q1_abr_2026, 0) + IFNULL(q2_abr_2026, 0) +
                IFNULL(q1_may_2026, 0) + IFNULL(q2_may_2026, 0)
            ) * precio_aplicado
        )
    INTO total_importe
    FROM proyecciones_cliente
    WHERE id_proyeccion = NEW.id_proyeccion;

    -- Actualizar proyecciones_ventas (con nuevas columnas)
    UPDATE proyecciones_ventas
    SET
        q1_sep_2025 = (SELECT IFNULL(SUM(q1_sep_2025), 0) FROM proyecciones_cliente WHERE id_proyeccion = NEW.id_proyeccion),
        q2_sep_2025 = (SELECT IFNULL(SUM(q2_sep_2025), 0) FROM proyecciones_cliente WHERE id_proyeccion = NEW.id_proyeccion),
        q1_oct_2025 = (SELECT IFNULL(SUM(q1_oct_2025), 0) FROM proyecciones_cliente WHERE id_proyeccion = NEW.id_proyeccion),
        q2_oct_2025 = (SELECT IFNULL(SUM(q2_oct_2025), 0) FROM proyecciones_cliente WHERE id_proyeccion = NEW.id_proyeccion),
        q1_nov_2025 = (SELECT IFNULL(SUM(q1_nov_2025), 0) FROM proyecciones_cliente WHERE id_proyeccion = NEW.id_proyeccion),
        q2_nov_2025 = (SELECT IFNULL(SUM(q2_nov_2025), 0) FROM proyecciones_cliente WHERE id_proyeccion = NEW.id_proyeccion),
        q1_dic_2025 = (SELECT IFNULL(SUM(q1_dic_2025), 0) FROM proyecciones_cliente WHERE id_proyeccion = NEW.id_proyeccion),
        q2_dic_2025 = (SELECT IFNULL(SUM(q2_dic_2025), 0) FROM proyecciones_cliente WHERE id_proyeccion = NEW.id_proyeccion),
        q1_mar_2026 = (SELECT IFNULL(SUM(q1_mar_2026), 0) FROM proyecciones_cliente WHERE id_proyeccion = NEW.id_proyeccion),
        q2_mar_2026 = (SELECT IFNULL(SUM(q2_mar_2026), 0) FROM proyecciones_cliente WHERE id_proyeccion = NEW.id_proyeccion),
        q1_abr_2026 = (SELECT IFNULL(SUM(q1_abr_2026), 0) FROM proyecciones_cliente WHERE id_proyeccion = NEW.id_proyeccion),
        q2_abr_2026 = (SELECT IFNULL(SUM(q2_abr_2026), 0) FROM proyecciones_cliente WHERE id_proyeccion = NEW.id_proyeccion),
        q1_may_2026 = (SELECT IFNULL(SUM(q1_may_2026), 0) FROM proyecciones_cliente WHERE id_proyeccion = NEW.id_proyeccion),
        q2_may_2026 = (SELECT IFNULL(SUM(q2_may_2026), 0) FROM proyecciones_cliente WHERE id_proyeccion = NEW.id_proyeccion),
        orden_total_cant = total_cantidad,
        orden_total_importe = total_importe
    WHERE id = NEW.id_proyeccion;
END */;;
