/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `actualizar_importe_total` AFTER DELETE ON `proyecciones_cliente` FOR EACH ROW BEGIN
  DECLARE cantidad INT DEFAULT 0;
  DECLARE importe DECIMAL(12,2) DEFAULT 0;

  SET cantidad = IFNULL(OLD.q1_sep_2025, 0) + IFNULL(OLD.q1_oct_2025, 0) + 
                 IFNULL(OLD.q1_nov_2025, 0) + IFNULL(OLD.q1_dic_2025, 0) +
                 IFNULL(OLD.q2_sep_2025, 0) + IFNULL(OLD.q2_oct_2025, 0) + 
