                 IFNULL(OLD.q2_abr_2026, 0) + IFNULL(OLD.q2_may_2026, 0);

  SET importe = cantidad * IFNULL(OLD.precio_aplicado, 0);

  UPDATE proyecciones_ventas
  SET orden_total_cant = IFNULL(orden_total_cant, 0) - cantidad,
      orden_total_importe = IFNULL(orden_total_importe, 0) - importe
  WHERE id = OLD.id_proyeccion;
END */;;
