--
-- Table structure for table `proyecciones_ventas`
--

DROP TABLE IF EXISTS `proyecciones_ventas`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `proyecciones_ventas` (
  `id` int NOT NULL AUTO_INCREMENT,
  `referencia` varchar(100) DEFAULT NULL,
  `clave_factura` varchar(100) DEFAULT NULL,
  `clave_6_digitos` varchar(20) DEFAULT NULL,
  `ean` varchar(100) DEFAULT NULL,
  `clave_odoo` varchar(100) DEFAULT NULL,
